import streamlit as st

st.set_page_config(page_title='IZ | Asistente de Carrera', page_icon='📚', layout='centered')

LOGO_B64 = ''

MODULOS = [
    'Centro de Operaciones', 'Semillero', 'Tareas', 'Radar', 'Estudio',
    'Calendario', 'Relaciones', 'Libros y relatos', 'Ideas para la app', 'Notas de voz'
]

if 'page' not in st.session_state:
    st.session_state.page = 'Centro de Operaciones'
if 'show_menu' not in st.session_state:
    st.session_state.show_menu = False
if 'semillas' not in st.session_state:
    st.session_state.semillas = [
        {'tipo': '🎙️ Nota de voz', 'texto': 'Idea para vídeo: ¿sabías que...? sobre libros antiguos', 'estado': 'Por organizar'},
        {'tipo': '💡 Idea', 'texto': 'Serie de contenidos sobre Madrid literario', 'estado': 'Por organizar'},
    ]
if 'tareas' not in st.session_state:
    st.session_state.tareas = [
        {'texto': 'Revisar calendario + noticias', 'hecha': False},
        {'texto': 'Preparar base de contactos', 'hecha': False},
        {'texto': 'Crear banco de contenidos', 'hecha': False},
    ]
if 'ideas_app' not in st.session_state:
    st.session_state.ideas_app = [
        'Menú superior compacto',
        'Cards clicables',
        'Notas de voz arriba junto al menú',
    ]


def go(page):
    st.session_state.page = page
    st.session_state.show_menu = False
    st.rerun()


def css():
    st.markdown('''
    <style>
    [data-testid="stAppViewContainer"] { background: linear-gradient(180deg, #fffaf3 0%, #f4eadc 100%); }
    [data-testid="stHeader"] {background: rgba(255,250,243,0.92);}
    .block-container { padding-top: 1rem; padding-bottom: 5rem; max-width: 760px; }
    .topbar { position: sticky; top: 0; z-index: 999; display:flex; align-items:center; justify-content:space-between; gap:12px; padding:10px 8px 12px 8px; background: rgba(255,250,243,0.96); backdrop-filter: blur(8px); border-bottom: 1px solid rgba(121,91,70,.08); }
    .brand {display:flex;align-items:center;gap:10px;}
    .brand img {width:54px;height:54px;border-radius:50%;object-fit:cover;box-shadow:0 4px 16px rgba(0,0,0,.08);}
    .brand strong {font-size:26px;letter-spacing:-.03em;color:#1f1f22;}
    .version {font-size:13px;color:#8b7768;border:1px solid #ead9c8;border-radius:999px;padding:5px 10px;background:#fffaf3;}
    .menu-panel { background:#fffaf6; border:1px solid #ead9c8; border-radius:22px; padding:12px; box-shadow:0 12px 32px rgba(55,40,25,.12); margin:6px 0 16px 0; }
    .hero { background: linear-gradient(135deg,#fffaf5 0%,#ead8c8 100%); border:1px solid #ead9c8; border-radius:34px; padding:34px 26px; box-shadow:0 18px 45px rgba(91,60,38,.08); margin: 12px 0 18px 0; }
    .hero h1 {font-size:42px;line-height:1.05;margin:0 0 18px 0;letter-spacing:-.05em;color:#1f1f22;}
    .hero p {font-size:20px;line-height:1.55;color:#756a63;margin:0;}
    .kpi-grid {display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin:12px 0 12px;}
    .kpi {background:#fffdfa;border:1px solid #ead9c8;border-radius:20px;padding:12px 8px;text-align:center;box-shadow:0 10px 26px rgba(91,60,38,.06);}
    .kpi strong {display:block;font-size:26px;color:#715294;line-height:1;}
    .kpi span {display:block;font-size:13px;color:#3d3937;margin-top:7px;}
    .soft-card {background:#fffdfa;border:1px solid #ead9c8;border-radius:28px;padding:24px;margin:14px 0;box-shadow:0 14px 34px rgba(91,60,38,.07);}
    .soft-card h2 {margin:0 0 12px 0;font-size:28px;letter-spacing:-.04em;}
    .soft-card p, .soft-card li {font-size:18px;line-height:1.55;color:#514b48;}
    .pill {display:inline-block;background:#eadccd;border:1px solid #d8c4b2;border-radius:999px;padding:8px 15px;margin:4px 4px 0 0;font-size:15px;}
    div.stButton > button { border-radius:18px !important; border:1px solid #ead9c8 !important; background:#fffdfa !important; color:#2a2726 !important; min-height:46px; box-shadow:0 8px 20px rgba(91,60,38,.05); font-weight:600; white-space: normal; }
    div.stButton > button:hover {border-color:#8b6aa8 !important; color:#6d4f88 !important;}
    @media (max-width: 640px) {
        .block-container {padding-left:1rem;padding-right:1rem;}
        .brand img {width:48px;height:48px;}
        .brand strong {font-size:24px;}
        .hero {padding:28px 22px;border-radius:32px;}
        .hero h1 {font-size:38px;}
        .hero p {font-size:19px;}
        .kpi-grid {grid-template-columns:repeat(2,1fr);gap:10px;}
        .kpi {padding:14px 8px;}
        .kpi strong {font-size:28px;}
    }
    </style>
    ''', unsafe_allow_html=True)


def header():
    logo_html = f'<img src="data:image/png;base64,{LOGO_B64}" alt="Irene Zurilla logo">' if LOGO_B64 else '<span style="font-size:42px">📚</span>'
    st.markdown(f'''
    <div class="topbar">
      <div class="brand">{logo_html}<strong>IZ</strong></div>
      <div class="version">V2.6 estable</div>
    </div>
    ''', unsafe_allow_html=True)
    c1, c2, c3 = st.columns([1, 1, 1])
    with c1:
        if st.button('🎙️ Notas', use_container_width=True):
            go('Notas de voz')
    with c2:
        if st.button('☰ Menú', use_container_width=True):
            st.session_state.show_menu = not st.session_state.show_menu
            st.rerun()
    with c3:
        if st.button('🏠 Centro', use_container_width=True):
            go('Centro de Operaciones')
    if st.session_state.show_menu:
        st.markdown('<div class="menu-panel">', unsafe_allow_html=True)
        rows = [MODULOS[i:i+2] for i in range(0, len(MODULOS), 2)]
        for row in rows:
            cols = st.columns(2)
            for idx, m in enumerate(row):
                with cols[idx]:
                    if st.button(m, key=f'menu_{m}', use_container_width=True):
                        go(m)
        st.markdown('</div>', unsafe_allow_html=True)


def hero(title, subtitle):
    st.markdown(f'<div class="hero"><h1>{title}</h1><p>{subtitle}</p></div>', unsafe_allow_html=True)


def kpis():
    tareas = sum(1 for t in st.session_state.tareas if not t['hecha'])
    semillas = len(st.session_state.semillas)
    st.markdown(f'''
    <div class="kpi-grid">
      <div class="kpi"><strong>{tareas}</strong><span>Tareas</span></div>
      <div class="kpi"><strong>{semillas}</strong><span>Semillas</span></div>
      <div class="kpi"><strong>4</strong><span>Oportunidades</span></div>
      <div class="kpi"><strong>2</strong><span>Eventos</span></div>
    </div>
    ''', unsafe_allow_html=True)
    c1, c2, c3, c4 = st.columns(4)
    with c1:
        if st.button('Tareas', key='kpi_tareas', use_container_width=True): go('Tareas')
    with c2:
        if st.button('Semillero', key='kpi_sem', use_container_width=True): go('Semillero')
    with c3:
        if st.button('Radar', key='kpi_rad', use_container_width=True): go('Radar')
    with c4:
        if st.button('Calendario', key='kpi_cal', use_container_width=True): go('Calendario')


def center():
    hero('Centro de Operaciones', 'Buenos días, Irene · Aquí está lo que necesita tu atención.')
    kpis()
    if st.button('🎯 Prioridad del día\nPreparar base de contactos · Crear banco de contenidos · Revisar agenda cultural', use_container_width=True):
        go('Tareas')
    if st.button('🔥 Radar rápido\n4 oportunidades detectadas para revisar esta semana', use_container_width=True):
        go('Radar')
    if st.button('📚 Libro activo\nEl libro mágico de Hugo e Inés · Fase: preparación de publicación', use_container_width=True):
        go('Libros y relatos')
    if st.button('🎙️ Última nota de voz\nIdea para vídeo: ¿sabías que...? sobre libros antiguos · Por organizar', use_container_width=True):
        go('Semillero')


def semillero():
    hero('Semillero', 'Notas, ideas y hallazgos que todavía no tienen destino definitivo.')
    tipo = st.selectbox('Tipo', ['🎙️ Nota de voz', '💡 Idea', '👤 Contacto', '📅 Evento', '🏆 Concurso', '📰 Noticia', '📚 Libro o relato'])
    texto = st.text_area('Contenido', placeholder='Guarda aquí algo que todavía no sabes dónde colocar...')
    if st.button('Guardar en Semillero', use_container_width=True):
        if texto.strip():
            st.session_state.semillas.insert(0, {'tipo': tipo, 'texto': texto.strip(), 'estado': 'Por organizar'})
            st.success('Guardado en Semillero')
    for item in st.session_state.semillas:
        st.markdown(f'<div class="soft-card"><h2>{item["tipo"]}</h2><p>{item["texto"]}</p><span class="pill">{item["estado"]}</span></div>', unsafe_allow_html=True)


def tareas():
    hero('Tareas', 'Lo que hay que hacer, separado de las ideas.')
    nueva = st.text_input('Nueva tarea')
    if st.button('Añadir tarea', use_container_width=True) and nueva.strip():
        st.session_state.tareas.append({'texto': nueva.strip(), 'hecha': False})
        st.rerun()
    st.markdown('<div class="soft-card"><h2>🔥 Hoy</h2></div>', unsafe_allow_html=True)
    for i, tarea in enumerate(st.session_state.tareas):
        st.session_state.tareas[i]['hecha'] = st.checkbox(tarea['texto'], value=tarea['hecha'], key=f'task_{i}')


def radar():
    hero('Radar', 'Oportunidades, eventos, concursos y señales del mundo literario.')
    tabs = st.tabs(['⭐ Recomendado', '🎤 Eventos', '🏆 Concursos', '📰 Noticias'])
    with tabs[0]:
        for txt in ['Presentación en FNAC Callao · Madrid', 'Concurso de relato histórico · cierra en 16 días', 'Buscar eventos de librerías en Getafe/Leganés']:
            st.markdown(f'<div class="soft-card"><h2>Oportunidad</h2><p>{txt}</p><span class="pill">Revisar</span></div>', unsafe_allow_html=True)
    with tabs[1]: st.info('Aquí aparecerán eventos y presentaciones.')
    with tabs[2]: st.info('Aquí aparecerán concursos literarios.')
    with tabs[3]: st.info('Aquí aparecerán noticias del sector.')


def estudio():
    hero('Estudio', 'Banco de contenidos y producción editorial.')
    for name, num in [('Ideas', 12), ('Guiones', 3), ('Pendientes de grabar', 5), ('Programados', 2)]:
        st.markdown(f'<div class="soft-card"><h2>🎬 {name}</h2><p>{num} elementos</p></div>', unsafe_allow_html=True)


def calendario():
    hero('Calendario', 'Fechas importantes, publicaciones, eventos y lanzamientos.')
    st.markdown('<div class="soft-card"><h2>📅 Esta semana</h2><p>Viernes · Radar del fin de semana<br>Domingo tarde · Reunión de Dirección</p></div>', unsafe_allow_html=True)
    st.markdown('<div class="soft-card"><h2>🗓 Próximas fechas</h2><p>Día del Libro · Sant Jordi · Navidad · Feria del Libro</p></div>', unsafe_allow_html=True)


def relaciones():
    hero('Relaciones', 'Contactos, librerías, bibliotecas, autores, prensa y editoriales.')
    for txt in ['Librería Cervantes · seguimiento', 'Biblioteca Getafe · pendiente', 'Editorial · contacto editorial']:
        st.markdown(f'<div class="soft-card"><h2>🤝 Contacto</h2><p>{txt}</p></div>', unsafe_allow_html=True)


def libros():
    hero('Libros y relatos', 'Todo lo terminado o en campaña: publicado o no publicado.')
    for title, estado in [('El libro mágico de Hugo e Inés', 'Preparación de publicación'), ('Preludio de un ocaso', 'Relato terminado'), ('La casa del ciervo', 'Cuento terminado')]:
        st.markdown(f'<div class="soft-card"><h2>📚 {title}</h2><p>{estado}</p></div>', unsafe_allow_html=True)


def ideas_app():
    hero('Ideas para la app', 'Mejoras que se te ocurran mientras la usas.')
    idea = st.text_input('Nueva idea para la app')
    if st.button('Guardar idea', use_container_width=True) and idea.strip():
        st.session_state.ideas_app.insert(0, idea.strip())
        st.rerun()
    for item in st.session_state.ideas_app:
        st.markdown(f'<div class="soft-card"><h2>💡 Idea</h2><p>{item}</p><span class="pill">Nueva</span></div>', unsafe_allow_html=True)


def notas():
    hero('Notas de voz', 'Captura rápida. De momento guarda texto; la grabación real llegará en la siguiente fase.')
    nota = st.text_area('Dictado / transcripción', placeholder='Escribe o pega aquí lo que has contado por voz...')
    destino = st.selectbox('Guardar como', ['🎙️ Nota de voz', '💡 Idea', '✅ Tarea', '💡 Idea para la app'])
    if st.button('Guardar nota', use_container_width=True):
        if nota.strip():
            if destino == '✅ Tarea':
                st.session_state.tareas.append({'texto': nota.strip(), 'hecha': False})
            elif destino == '💡 Idea para la app':
                st.session_state.ideas_app.insert(0, nota.strip())
            else:
                st.session_state.semillas.insert(0, {'tipo': destino, 'texto': nota.strip(), 'estado': 'Por organizar'})
            st.success('Guardado')

css()
header()
page = st.session_state.page
if page == 'Centro de Operaciones': center()
elif page == 'Semillero': semillero()
elif page == 'Tareas': tareas()
elif page == 'Radar': radar()
elif page == 'Estudio': estudio()
elif page == 'Calendario': calendario()
elif page == 'Relaciones': relaciones()
elif page == 'Libros y relatos': libros()
elif page == 'Ideas para la app': ideas_app()
elif page == 'Notas de voz': notas()
